	if (!doc) {
		throw error(404, `document ${params.path} not found`);
	}

	throw redirect(
		308,
		`/nodes/${params.nodeId}/projects/${params.projectId}/artifacts/${encodeURIComponent(`doc:${doc.id}`)}`
	);
};

